fun solve(prices: Array<Long>, strategy: Array<Long>, k: Long): Long {
    val n = prices.size
    var maxProfit = 0L

    // Calculate the original profit
    var originalProfit = 0L
    for (i in strategy.indices) {
        originalProfit += strategy[i] * prices[i]
    }
    maxProfit = originalProfit

    // Try to modify each possible subarray of length k
    val halfK = k / 2
    for (i in 0 until n - k + 1) {
        // Calculate the profit if we modify the subarray starting at i
        var modifiedProfit = originalProfit

        // For the first k/2 elements, change from -1 to 0 (hold)
        for (j in i until i + halfK) {
            if (strategy[j] == -1L) {
                modifiedProfit -= strategy[j] * prices[j]
                modifiedProfit += 0 * prices[j]
            }
        }

        // For the next k/2 elements, change from 0 to 1 (sell)
        for (j in i + halfK until i + k) {
            if (strategy[j] == 0L) {
                modifiedProfit -= strategy[j] * prices[j]
                modifiedProfit += 1 * prices[j]
            }
        }

        maxProfit = maxOf(maxProfit, modifiedProfit)
    }

    return maxProfit
}
